const sheetsData = $('Fetch Google Sheets Data').first().json;
const kintoneData = $('Fetch kintone Records').first().json;

const sheetRows = (sheetsData.values || []).map(row => ({
  id: row[0],           // Column A: Record ID
  company: row[1],      // Column B: Company name
  contact: row[2],      // Column C: Contact person
  status: row[3],       // Column D: Status
  amount: row[4],       // Column E: Amount
  updated: row[5]       // Column F: Last updated
}));

const kintoneRecords = (kintoneData.records || []).map(rec => ({
  id: rec['$id'].value,
  company: rec['会社名']?.value || '',
  contact: rec['担当者']?.value?.[0]?.name || '',
  status: rec['ステータス']?.value || '',
  amount: rec['売上見込']?.value || '0',
  updated: rec['更新日時']?.value || ''
}));

// Find records to create in kintone (in sheets but not kintone)
const kintoneIds = new Set(kintoneRecords.map(r => r.id));
const toCreate = sheetRows.filter(r => r.id && !kintoneIds.has(r.id) && r.id.startsWith('NEW-'));

// Find records to update in kintone (different data)
const toUpdate = sheetRows.filter(row => {
  const ktRecord = kintoneRecords.find(kr => kr.id === row.id);
  if (!ktRecord) return false;
  return ktRecord.status !== row.status || ktRecord.amount !== row.amount;
});

// Find records to sync back to sheets (new in kintone)
const sheetIds = new Set(sheetRows.map(r => r.id));
const toSyncBack = kintoneRecords.filter(r => !sheetIds.has(r.id));

return [
  { json: { action: 'create', records: toCreate, count: toCreate.length } },
  { json: { action: 'update', records: toUpdate, count: toUpdate.length } },
  { json: { action: 'sync_back', records: toSyncBack, count: toSyncBack.length } }
];

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  if (data.action === 'create' && data.records.length > 0) {
    // Prepare kintone create payload
    const kintoneRecords = data.records.map(r => ({
      '会社名': { value: r.company },
      'ステータス': { value: r.status },
      '売上見込': { value: r.amount }
    }));
    results.push({
      json: {
        action: 'create',
        endpoint: `https://${process.env.KINTONE_DOMAIN}/k/v1/records.json`,
        payload: {
          app: process.env.KINTONE_APP_ID,
          records: kintoneRecords
        },
        count: data.records.length
      }
    });
  }

  if (data.action === 'update' && data.records.length > 0) {
    const kintoneUpdates = data.records.map(r => ({
      id: r.id,
      record: {
        'ステータス': { value: r.status },
        '売上見込': { value: r.amount }
      }
    }));
    results.push({
      json: {
        action: 'update',
        endpoint: `https://${process.env.KINTONE_DOMAIN}/k/v1/records.json`,
        payload: {
          app: process.env.KINTONE_APP_ID,
          records: kintoneUpdates
        },
        count: data.records.length
      }
    });
  }
}

return results.length > 0 ? results : [{ json: { action: 'none', count: 0 } }];

