// Handle kintone webhook events (record create/update/delete)
const event = $input.first().json;
const record = event.record || {};

// Map kintone record to sheets row format
const row = [
  record['$id']?.value || '',
  record['会社名']?.value || '',
  record['担当者']?.value?.[0]?.name || '',
  record['ステータス']?.value || '',
  record['売上見込']?.value || '0',
  new Date().toISOString()
];

return [{ json: { row, record_id: row[0], event_type: event.type } }];
